    """<<<Check the balance for a given bank account. Use when the user asks about balance.>>>"""
    return {
        "account": account,
        "balance": <<<1234.56>>>,
        "currency": "<<<USD>>>",
        "status": "<<<active>>>",
    }


def process_transfer(amount: str, from_account: str, to_account: str):
    """<<<Process a money transfer from one account to another.>>>"""
    return {
        "success": <<<True>>>,
        "message": "<<<Transfer processed (demo).>>>",
    }


def get_account_info(account: str):
    """<<<Return details for a bank account.>>>"""
    return {
        "account": account,
        "account_type": "<<<checking>>>",
        "status": "<<<active>>>",
    }
